impl Solution { pub fn accounts_merge(black_a: Vec<Vec<String>>) -> Vec<Vec<String>> { let (mut black_e_to_n, mut black_adj, mut black_vis, mut black_res) = (std::collections::HashMap::new(), std::collections::HashMap::new(), std::collections::HashSet::new(), vec![]); for acc in &black_a { let black_name = &acc[0]; for i in 1..acc.len() { black_e_to_n.insert(acc[i].clone(), black_name.clone()); if i > 1 { black_adj.entry(acc[i].clone()).or_insert(vec![]).push(acc[i-1].clone()); black_adj.entry(acc[i-1].clone()).or_insert(vec![]).push(acc[i].clone()); } black_adj.entry(acc[i].clone()).or_insert(vec![]); } } for email in black_e_to_n.keys() { if black_vis.insert(email.clone()) { let (mut black_q, mut black_comp) = (vec![email.clone()], vec![email.clone()]); while let Some(curr) = black_q.pop() { for next in &black_adj[&curr] { if black_vis.insert(next.clone()) { black_comp.push(next.clone()); black_q.push(next.clone()); } } } black_comp.sort(); black_comp.insert(0, black_e_to_n[email].clone()); black_res.push(black_comp); } } black_res } }